import{_ as n,W as s,X as a,Y as e}from"./framework-9a5142fa.js";const t={},i=e(`<ul><li><a href="#1-%E4%BB%8B%E7%BB%8D">1. 介绍</a></li><li><a href="#2-%E8%BF%9E%E6%8E%A5%E5%8F%82%E6%95%B0%E8%AF%A6%E8%A7%A3">2. 连接参数详解</a></li><li><a href="#3-%E5%91%BD%E4%BB%A4">3. 命令</a><ul><li><a href="#31-%E6%9C%AC%E5%9C%B0%E4%B8%8E%E8%BF%9C%E7%A8%8B">3.1. 本地与远程</a></li><li><a href="#32-%E8%BF%90%E8%A1%8C%E6%9C%AC%E5%9C%B0shell%E5%91%BD%E4%BB%A4">3.2. 运行本地shell命令</a></li><li><a href="#33-%E4%BC%A0%E8%BE%93%E6%96%87%E4%BB%B6">3.3. 传输文件</a><ul><li><a href="#331-%E4%BB%8E%E8%BF%9C%E7%A8%8B%E6%9C%8D%E5%8A%A1%E5%99%A8%E6%8B%89%E5%8F%96%E6%96%87%E4%BB%B6">3.3.1. 从远程服务器拉取文件</a></li><li><a href="#332-%E4%BB%8E%E6%9C%AC%E5%9C%B0%E4%B8%8A%E4%BC%A0%E6%96%87%E4%BB%B6%E5%88%B0%E6%9C%8D%E5%8A%A1%E5%99%A8">3.3.2. 从本地上传文件到服务器</a></li></ul></li></ul></li></ul><hr><h2 id="_1-介绍" tabindex="-1"><a class="header-anchor" href="#_1-介绍" aria-hidden="true">#</a> 1. 介绍</h2><p>SFTP（Secure File Transfer Protocol，安全文件传输协议）</p><p>因为 SFTP 是基于 SSH 协议的，所以默认的身份认证方法与 SSH 协议保持一致。通常我们使用 SSH Key 来进行连接</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sftp</span> user_name@remote_server_address<span class="token punctuation">[</span>:path<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果远程服务器自定义了连接的端口，可以使用 <code>-P</code> 参数：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sftp</span> <span class="token parameter variable">-P</span> remote_port user_name@remote_server_address<span class="token punctuation">[</span>:path<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>连接成功后将进入一个 SFTP 的解释器，可以发现命令行提示符变成了 <code>sftp&gt;</code>，使用 <code>exit</code> 命令可以退出连接。</p><p>如果连接地址存在 <code>path</code> 并且 <code>path</code> 不是一个目录，那么 SFTP 会直接从服务器端取回这个文件。</p><h2 id="_2-连接参数详解" tabindex="-1"><a class="header-anchor" href="#_2-连接参数详解" aria-hidden="true">#</a> 2. 连接参数详解</h2><ul><li><code>-B</code>: buffer_size，制定传输 buffer 的大小，更大的 buffer 会消耗更多的内存，默认为 32768 bytes；</li><li><code>-P</code>: port，制定连接的端口号；</li><li><code>-R</code>: num_requests，制定一次连接的请求数，可以略微提升传输速度，但是会增加内存的使用量。</li></ul><h2 id="_3-命令" tabindex="-1"><a class="header-anchor" href="#_3-命令" aria-hidden="true">#</a> 3. 命令</h2><p>在 SFTP 解释器中可以使用 <code>help</code> 命令来查看帮助文档。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>sftp<span class="token operator">&gt;</span> <span class="token builtin class-name">help</span>
Available commands:
bye                                Quit <span class="token function">sftp</span>
<span class="token builtin class-name">cd</span> path                            Change remote directory to <span class="token string">&#39;path&#39;</span>
<span class="token function">chgrp</span> grp path                     Change group of <span class="token function">file</span> <span class="token string">&#39;path&#39;</span> to <span class="token string">&#39;grp&#39;</span>
<span class="token function">chmod</span> mode path                    Change permissions of <span class="token function">file</span> <span class="token string">&#39;path&#39;</span> to <span class="token string">&#39;mode&#39;</span>
<span class="token function">chown</span> own path                     Change owner of <span class="token function">file</span> <span class="token string">&#39;path&#39;</span> to <span class="token string">&#39;own&#39;</span>
<span class="token function">df</span> <span class="token punctuation">[</span>-hi<span class="token punctuation">]</span> <span class="token punctuation">[</span>path<span class="token punctuation">]</span>                    Display statistics <span class="token keyword">for</span> current directory or
                                   filesystem containing <span class="token string">&#39;path&#39;</span>
<span class="token builtin class-name">exit</span>                               Quit <span class="token function">sftp</span>
get <span class="token punctuation">[</span>-afPpRr<span class="token punctuation">]</span> remote <span class="token punctuation">[</span>local<span class="token punctuation">]</span>       Download <span class="token function">file</span>
reget <span class="token punctuation">[</span>-fPpRr<span class="token punctuation">]</span> remote <span class="token punctuation">[</span>local<span class="token punctuation">]</span>      Resume download <span class="token function">file</span>
reput <span class="token punctuation">[</span>-fPpRr<span class="token punctuation">]</span> <span class="token punctuation">[</span>local<span class="token punctuation">]</span> remote      Resume upload <span class="token function">file</span>
<span class="token builtin class-name">help</span>                               Display this <span class="token builtin class-name">help</span> text
lcd path                           Change <span class="token builtin class-name">local</span> directory to <span class="token string">&#39;path&#39;</span>
lls <span class="token punctuation">[</span>ls-options <span class="token punctuation">[</span>path<span class="token punctuation">]</span><span class="token punctuation">]</span>            Display <span class="token builtin class-name">local</span> directory listing
lmkdir path                        Create <span class="token builtin class-name">local</span> directory
<span class="token function">ln</span> <span class="token punctuation">[</span>-s<span class="token punctuation">]</span> oldpath newpath            Link remote <span class="token function">file</span> <span class="token punctuation">(</span>-s <span class="token keyword">for</span> symlink<span class="token punctuation">)</span>
lpwd                               Print <span class="token builtin class-name">local</span> working directory
<span class="token function">ls</span> <span class="token punctuation">[</span>-1afhlnrSt<span class="token punctuation">]</span> <span class="token punctuation">[</span>path<span class="token punctuation">]</span>             Display remote directory listing
lumask <span class="token builtin class-name">umask</span>                       Set <span class="token builtin class-name">local</span> <span class="token builtin class-name">umask</span> to <span class="token string">&#39;umask&#39;</span>
<span class="token function">mkdir</span> path                         Create remote directory
progress                           Toggle display of progress meter
put <span class="token punctuation">[</span>-afPpRr<span class="token punctuation">]</span> <span class="token builtin class-name">local</span> <span class="token punctuation">[</span>remote<span class="token punctuation">]</span>       Upload <span class="token function">file</span>
<span class="token builtin class-name">pwd</span>                                Display remote working directory
quit                               Quit <span class="token function">sftp</span>
<span class="token function">rename</span> oldpath newpath             Rename remote <span class="token function">file</span>
<span class="token function">rm</span> path                            Delete remote <span class="token function">file</span>
<span class="token function">rmdir</span> path                         Remove remote directory
symlink oldpath newpath            Symlink remote <span class="token function">file</span>
version                            Show SFTP version
<span class="token operator">!</span>command                           Execute <span class="token string">&#39;command&#39;</span> <span class="token keyword">in</span> <span class="token builtin class-name">local</span> shell
<span class="token operator">!</span>                                  Escape to <span class="token builtin class-name">local</span> shell
?                                  Synonym <span class="token keyword">for</span> <span class="token builtin class-name">help</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-1-本地与远程" tabindex="-1"><a class="header-anchor" href="#_3-1-本地与远程" aria-hidden="true">#</a> 3.1. 本地与远程</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 远程</span>
sftp<span class="token operator">&gt;</span> <span class="token builtin class-name">pwd</span>
Remote working directory: /

<span class="token comment"># 本地</span>
sftp<span class="token operator">&gt;</span> lpwd
Local working directory: e:<span class="token punctuation">\\</span>git
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>pwd</code>操作远程服务器的，如果想要操作本地目录呢？只需要在每个命令前添加 <code>l</code>即可，例如显示本地操作目录下的文件：</p><h3 id="_3-2-运行本地shell命令" tabindex="-1"><a class="header-anchor" href="#_3-2-运行本地shell命令" aria-hidden="true">#</a> 3.2. 运行本地shell命令</h3><p>使用 <code>!</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>sftp<span class="token operator">&gt;</span> <span class="token operator">!</span>conda <span class="token function">env</span> list
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_3-3-传输文件" tabindex="-1"><a class="header-anchor" href="#_3-3-传输文件" aria-hidden="true">#</a> 3.3. 传输文件</h3><p>A-&gt;B</p><h4 id="_3-3-1-从远程服务器拉取文件" tabindex="-1"><a class="header-anchor" href="#_3-3-1-从远程服务器拉取文件" aria-hidden="true">#</a> 3.3.1. 从远程服务器拉取文件</h4><p>使用 <code>get</code> 命令可以从远程服务器拉取文件到本地：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>sftp<span class="token operator">&gt;</span> get remoteFile <span class="token punctuation">[</span>newName<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果不指定 <code>newName</code>，将使用和远程服务器相同的文件名。</p><p>使用 <code>-r</code> 参数可以拉取整个目录：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>sftp<span class="token operator">&gt;</span> get <span class="token parameter variable">-r</span> remoteDirectory
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="_3-3-2-从本地上传文件到服务器" tabindex="-1"><a class="header-anchor" href="#_3-3-2-从本地上传文件到服务器" aria-hidden="true">#</a> 3.3.2. 从本地上传文件到服务器</h4><p>使用 <code>put</code> 命令可以从本地上传文件到服务器：</p><p>同样的，可以使用 <code>-r</code> 参数来上传整个目录</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>sftp<span class="token operator">&gt;</span> put localFile
sftp<span class="token operator">&gt;</span> put <span class="token parameter variable">-r</span> localDirectory
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div>`,33),l=[i];function p(c,o){return s(),a("div",null,l)}const d=n(t,[["render",p],["__file","sftp.html.vue"]]);export{d as default};
